@app.route("/login", methods=["POST"])
def login():
    payload = request.get_json(silent=True) or {}
    user_id = payload.get("user_id")
    if not user_id:
        return jsonify({"error": "user_id is required"}), 400

    session_id = os.urandom(24).hex()
