    g.session = {
        "user_id": user_id,
        "logged_in": True,
        "created_at": int(time.time()),
    }

    response = make_response(jsonify({"message": "logged in", "session_id": session_id}), 200)
    response.set_cookie(
        SESSION_COOKIE_NAME,
        session_id,
        max_age=SESSION_TTL_SECONDS,
        httponly=True,
        samesite="Lax",
    )
